// S3 lifecycle: tier request-log data by age, then delete
{
  "Rules": [{
    "ID": "request-logs-tiering",
    "Status": "Enabled",
    "Filter": {"Prefix": "logs/request/"},
    "Transitions": [
      {"Days": 7,  "StorageClass": "STANDARD_IA"},   // warm
      {"Days": 30, "StorageClass": "GLACIER_IR"}      // cold
    ],
    "Expiration": {"Days": 180}                        // delete
  }, {
    "ID": "debug-logs-short",
    "Status": "Enabled",
    "Filter": {"Prefix": "logs/debug/"},
    "Expiration": {"Days": 14}                          // low value, short life
  }]
}

# Downsample a trace batch on transition to cheaper storage
import random

def downsample_for_archive(traces, success_rate=0.1):
    keep, rolled = [], []
    for tr in traces:
        if tr["has_error"] or tr["duration_ms"] > tr["slow_threshold_ms"]:
            keep.append(tr)                       # always keep errors + slow
        elif random.random() < success_rate:
            keep.append(strip_verbose_attrs(tr))  # sampled, slimmed
        else:
            rolled.append(tr["duration_ms"])      # into a histogram only
    return keep, latency_histogram(rolled)

def latency_histogram(durations, buckets=(50, 100, 250, 500, 1000, 2500)):
    hist = {b: 0 for b in buckets}
    hist["inf"] = 0
    for d in durations:
        placed = False
        for b in buckets:
            if d <= b:
                hist[b] += 1; placed = True; break
        if not placed:
            hist["inf"] += 1
    return hist
